import React, { useState, useEffect } from 'react';
import { getEventsByOrganiser, createEvent, updateEvent, deleteEvent, getAllLocations, createSlot } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

// ── Constants ─────────────────────────────────────────────────────────────────
const EMPTY_FORM = {
  name: '', type: 'MOVIE', genres: [], languages: [], venues: [],
  duration: '', categoryName: '', status: 'ACTIVE',
};
const EMPTY_SLOT = { showDate: '', startTime: '', endTime: '' };

const TYPES         = ['MOVIE', 'CONCERT', 'EVENT'];
const ALL_GENRES    = ['Action','Drama','Comedy','Romance','Horror','Thriller','Pop','Rock','Classical','Festival','Sports','Cultural','Other'];
const ALL_LANGUAGES = ['English','Tamil','Hindi','Telugu','Malayalam','Kannada','French','Japanese'];

const TYPE_COLOR = { MOVIE: 'var(--blue)', CONCERT: 'var(--gold)', EVENT: 'var(--green)' };

const STATUS_STYLE = {
  ACTIVE:    { bg: '#e8fff5', color: '#1a8f63', border: '#b2e8d0' },
  CANCELLED: { bg: '#fff0f0', color: '#b91c1c', border: '#fca5a5' },
  COMPLETED: { bg: '#eff6ff', color: '#2563a8', border: '#bfdbfe' },
};

const parseList = (str) => (!str ? [] : str.split(',').map((s) => s.trim()).filter(Boolean));

// ── Tag multi-select ──────────────────────────────────────────────────────────
const TagPicker = ({ label, options, selected, onChange }) => (
  <div className="form-group">
    <label className="form-label">
      {label} <span style={{ fontWeight: 400, color: 'var(--text-muted)', fontSize: '11px' }}>(select one or more)</span>
    </label>
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '7px' }}>
      {options.map((opt) => {
        const active = selected.includes(opt);
        return (
          <button key={opt} type="button"
            onClick={() => onChange(active ? selected.filter((x) => x !== opt) : [...selected, opt])}
            style={{
              padding: '5px 13px', borderRadius: '20px', border: '1.5px solid',
              fontSize: '12px', fontWeight: 600, cursor: 'pointer',
              fontFamily: 'var(--font-body)', transition: 'all 0.15s',
              borderColor: active ? 'var(--accent)' : 'var(--border)',
              background:  active ? 'var(--accent-dim)' : 'var(--bg-secondary)',
              color:       active ? 'var(--accent)' : 'var(--text-secondary)',
            }}>
            {active && '✓ '}{opt}
          </button>
        );
      })}
    </div>
    {selected.length > 0 && (
      <div style={{ marginTop: '7px', fontSize: '12px', color: 'var(--text-muted)' }}>
        Selected: <span style={{ color: 'var(--accent)', fontWeight: 700 }}>{selected.join(', ')}</span>
      </div>
    )}
  </div>
);

// ── Venue multi-select ────────────────────────────────────────────────────────
const VenuePicker = ({ locations, selected, onChange }) => (
  <div className="form-group" style={{ gridColumn: '1/-1' }}>
    <label className="form-label">
      Venue / Address <span style={{ fontWeight: 400, color: 'var(--text-muted)', fontSize: '11px' }}>(select one or more)</span>
    </label>
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '7px' }}>
      {locations.map((l) => {
        const active = selected.includes(l.locationId);
        return (
          <button key={l.locationId} type="button"
            onClick={() => onChange(active ? selected.filter((x) => x !== l.locationId) : [...selected, l.locationId])}
            style={{
              padding: '6px 14px', borderRadius: '10px', border: '1.5px solid',
              fontSize: '12px', fontWeight: 600, cursor: 'pointer',
              fontFamily: 'var(--font-body)', transition: 'all 0.15s',
              borderColor: active ? 'var(--accent)' : 'var(--border)',
              background:  active ? 'var(--accent-dim)' : 'var(--bg-secondary)',
              color:       active ? 'var(--accent)' : 'var(--text-secondary)',
            }}>
            {active && '✓ '}📍 {l.locName}{l.address ? ` — ${l.address}` : ''}
          </button>
        );
      })}
    </div>
    {selected.length > 0 && (
      <div style={{ marginTop: '7px', fontSize: '12px', color: 'var(--text-muted)' }}>
        {selected.length} venue{selected.length > 1 ? 's' : ''} selected
      </div>
    )}
  </div>
);

// ── Main Page ─────────────────────────────────────────────────────────────────
const AdminEventsPage = () => {
  const { user } = useAuth();
  const [events, setEvents]       = useState([]);
  const [locations, setLocations] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [modal, setModal]         = useState(false);
  const [form, setForm]           = useState(EMPTY_FORM);
  const [slots, setSlots]         = useState([{ ...EMPTY_SLOT }]); // slot rows
  const [editId, setEditId]       = useState(null);
  const [saving, setSaving]       = useState(false);

  const load = async () => {
    try {
      const [evRes, locRes] = await Promise.all([
        getEventsByOrganiser(user.userId),
        getAllLocations(),
      ]);
      setEvents(Array.isArray(evRes.data?.data) ? evRes.data.data : []);
      setLocations(Array.isArray(locRes.data?.data) ? locRes.data.data : []);
    } catch { toast.error('Failed to load events'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const openCreate = () => {
    setForm(EMPTY_FORM);
    setSlots([{ ...EMPTY_SLOT }]);
    setEditId(null);
    setModal(true);
  };

  const openEdit = (e) => {
    setForm({
      name:         e.name         || '',
      type:         e.type         || 'MOVIE',
      genres:       parseList(e.genre),
      languages:    parseList(e.language),
      // venues stored as locationIds — map from locName back to locationId
      venues:       parseList(e.summary).map((name) => {
        const found = locations.find((l) => l.locName === name);
        return found ? found.locationId : null;
      }).filter(Boolean),
      duration:     e.duration     || '',
      categoryName: e.categoryName || '',
      status:       e.status       || 'ACTIVE',
    });
    setSlots([{ ...EMPTY_SLOT }]); // reset slot rows on edit
    setEditId(e.eventId);
    setModal(true);
  };

  const handle = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // ── Slot row helpers ────────────────────────────────────────────────────────
  const addSlotRow    = () => setSlots((prev) => [...prev, { ...EMPTY_SLOT }]);
  const removeSlotRow = (i) => setSlots((prev) => prev.filter((_, idx) => idx !== i));
  const updateSlotRow = (i, key, val) =>
    setSlots((prev) => prev.map((s, idx) => idx === i ? { ...s, [key]: val } : s));

  // ── Save ────────────────────────────────────────────────────────────────────
  const save = async () => {
    if (!form.name.trim()) { toast.error('Event name is required'); return; }

    // Build venue name string from selected locationIds
    const venueNames = form.venues.map((id) => {
      const loc = locations.find((l) => l.locationId === id);
      return loc ? loc.locName : '';
    }).filter(Boolean);

    setSaving(true);
    try {
      const payload = {
        name:         form.name,
        type:         form.type,
        status:       form.status,
        duration:     form.duration,
        categoryName: form.categoryName,
        genre:        form.genres.join(','),
        language:     form.languages.join(','),
        summary:      venueNames.join(','),
        organiserId:  user.userId,
      };

      let savedEventId = editId;

      if (editId) {
        await updateEvent(editId, payload);
        toast.success('Event updated!');
      } else {
        const res = await createEvent(payload);
        savedEventId = res.data?.data?.eventId;
        toast.success('Event created!');
      }

      // ── Auto-create slots for each venue × each slot row ─────────────────
      if (!editId && savedEventId && form.venues.length > 0) {
        const filledSlots = slots.filter((s) => s.showDate && s.startTime);
        if (filledSlots.length > 0) {
          const slotPromises = [];
          for (const venueId of form.venues) {
            for (const slotRow of filledSlots) {
              slotPromises.push(
                createSlot({
                  eventId:    savedEventId,
                  locationId: venueId,
                  showDate:   slotRow.showDate,
                  startTime:  slotRow.startTime,
                  endTime:    slotRow.endTime || null,
                  slotStatus: 'AVAILABLE',
                })
              );
            }
          }
          await Promise.allSettled(slotPromises);
          toast.success(`${slotPromises.length} slot${slotPromises.length > 1 ? 's' : ''} created automatically!`);
        }
      }

      setModal(false);
      load();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to save'); }
    finally { setSaving(false); }
  };

  const del = async (id) => {
    if (!window.confirm('Delete this event?')) return;
    try { await deleteEvent(id); toast.success('Event deleted'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Delete failed'); }
  };

  // Check if event is editable
  const isEditable = (status) => status === 'ACTIVE';

  return (
    <div className="container page-content" style={{ background: 'var(--bg-secondary)', minHeight: '100vh', paddingLeft: '28px', paddingRight: '28px' }}>

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 className="page-title">MY EVENTS</h1>
          <p className="page-subtitle">{events.length} events managed</p>
        </div>
        <button onClick={openCreate} className="btn btn-primary">➕ Create Event</button>
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : events.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">🎭</div>
          <h3>No Events Yet</h3>
          <button onClick={openCreate} className="btn btn-primary" style={{ marginTop: '16px' }}>Create Event</button>
        </div>
      ) : (
        <div className="grid-3">
          {events.map((e) => {
            const genres    = parseList(e.genre);
            const languages = parseList(e.language);
            const venues    = parseList(e.summary);
            const ss        = STATUS_STYLE[e.status] || STATUS_STYLE.ACTIVE;
            const editable  = isEditable(e.status);

            return (
              <div key={e.eventId} className="card" style={{
                padding: '20px',
                borderTop: `3px solid ${TYPE_COLOR[e.type] || 'var(--accent)'}`,
                opacity: editable ? 1 : 0.85,
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                  {/* ── Fixed status badge ── */}
                  <span style={{
                    fontSize: '11px', fontWeight: 700, padding: '3px 10px', borderRadius: '20px',
                    background: ss.bg, color: ss.color, border: `1px solid ${ss.border}`,
                  }}>
                    {e.status}
                  </span>
                  <span style={{ fontSize: '12px', color: TYPE_COLOR[e.type], fontWeight: 600 }}>{e.type}</span>
                </div>

                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', marginBottom: '8px' }}>{e.name}</h3>

                {genres.length > 0 && (
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px', marginBottom: '6px' }}>
                    {genres.map((g) => (
                      <span key={g} style={{ fontSize: '10px', fontWeight: 700, padding: '2px 7px', borderRadius: '20px', background: 'var(--bg-secondary)', border: '1px solid var(--border)', color: 'var(--text-secondary)' }}>{g}</span>
                    ))}
                  </div>
                )}

                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '4px' }}>
                  🌐 {languages.join(', ') || '—'} &nbsp;·&nbsp; ⏱ {e.duration || '—'}
                </div>

                {venues.length > 0 && (
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', marginBottom: '10px' }}>
                    {venues.map((v) => (
                      <span key={v} style={{ fontSize: '11px', color: 'var(--text-secondary)', fontWeight: 600 }}>📍 {v}</span>
                    ))}
                  </div>
                )}

                {/* Cancelled/Completed notice */}
                {!editable && (
                  <div style={{
                    fontSize: '11px', padding: '6px 10px', borderRadius: '6px', marginBottom: '10px',
                    background: ss.bg, color: ss.color, border: `1px solid ${ss.border}`, fontWeight: 600,
                  }}>
                    {e.status === 'CANCELLED' ? '🚫 Event cancelled — slots locked' : '✅ Event completed — slots locked'}
                  </div>
                )}

                <div style={{ display: 'flex', gap: '8px', paddingTop: '12px', borderTop: '1px solid var(--border)' }}>
                  <button
                    onClick={() => editable && openEdit(e)}
                    disabled={!editable}
                    className="btn btn-secondary btn-sm"
                    style={{ flex: 1, opacity: editable ? 1 : 0.4, cursor: editable ? 'pointer' : 'not-allowed' }}
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => del(e.eventId)}
                    className="btn btn-danger btn-sm"
                    style={{ flex: 1 }}
                  >
                    Delete
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* ── Modal ── */}
      {modal && (
        <div className="modal-overlay" onClick={() => setModal(false)}>
          <div className="modal" style={{ maxWidth: '640px', maxHeight: '90vh', overflowY: 'auto' }} onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editId ? 'EDIT EVENT' : 'CREATE EVENT'}</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>

              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label">Event Name *</label>
                <input className="form-input" value={form.name} onChange={(e) => handle('name', e.target.value)} placeholder="e.g. AR Rahman Live" />
              </div>

              <div className="form-group">
                <label className="form-label">Type</label>
                <select className="form-input" value={form.type} onChange={(e) => handle('type', e.target.value)}>
                  {TYPES.map((t) => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Status</label>
                <select className="form-input" value={form.status} onChange={(e) => handle('status', e.target.value)}>
                  {['ACTIVE', 'COMPLETED', 'CANCELLED'].map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Duration</label>
                <input className="form-input" value={form.duration} onChange={(e) => handle('duration', e.target.value)} placeholder="2h 30min" />
              </div>

              <div className="form-group">
                <label className="form-label">Category</label>
                <input className="form-input" value={form.categoryName} onChange={(e) => handle('categoryName', e.target.value)} placeholder="e.g. Blockbuster" />
              </div>

              <div style={{ gridColumn: '1/-1' }}>
                <TagPicker label="Language" options={ALL_LANGUAGES} selected={form.languages} onChange={(v) => handle('languages', v)} />
              </div>

              <div style={{ gridColumn: '1/-1' }}>
                <TagPicker label="Genre" options={ALL_GENRES} selected={form.genres} onChange={(v) => handle('genres', v)} />
              </div>

              <VenuePicker locations={locations} selected={form.venues} onChange={(v) => handle('venues', v)} />

            </div>

            {/* ── Slot rows — only shown when creating ── */}
            {!editId && (
              <div style={{ marginTop: '20px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                  <label className="form-label" style={{ marginBottom: 0 }}>
                    Show Dates & Times
                    <span style={{ fontWeight: 400, color: 'var(--text-muted)', fontSize: '11px', marginLeft: '6px' }}>
                      (auto-creates slots for all selected venues)
                    </span>
                  </label>
                  <button type="button" onClick={addSlotRow}
                    className="btn btn-secondary btn-sm" style={{ fontSize: '12px' }}>
                    + Add Row
                  </button>
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                  {slots.map((s, i) => (
                    <div key={i} style={{
                      display: 'grid', gridTemplateColumns: '1fr 1fr 1fr auto',
                      gap: '8px', alignItems: 'end',
                      padding: '12px', borderRadius: '10px',
                      background: 'var(--bg-secondary)', border: '1px solid var(--border)',
                    }}>
                      <div className="form-group" style={{ marginBottom: 0 }}>
                        <label className="form-label" style={{ fontSize: '11px' }}>Date *</label>
                        <input type="date" className="form-input" value={s.showDate}
                          onChange={(e) => updateSlotRow(i, 'showDate', e.target.value)} />
                      </div>
                      <div className="form-group" style={{ marginBottom: 0 }}>
                        <label className="form-label" style={{ fontSize: '11px' }}>Start Time *</label>
                        <input type="time" className="form-input" value={s.startTime}
                          onChange={(e) => updateSlotRow(i, 'startTime', e.target.value)} />
                      </div>
                      <div className="form-group" style={{ marginBottom: 0 }}>
                        <label className="form-label" style={{ fontSize: '11px' }}>End Time</label>
                        <input type="time" className="form-input" value={s.endTime}
                          onChange={(e) => updateSlotRow(i, 'endTime', e.target.value)} />
                      </div>
                      <button type="button" onClick={() => removeSlotRow(i)}
                        disabled={slots.length === 1}
                        className="btn btn-danger btn-sm"
                        style={{ marginBottom: '0', opacity: slots.length === 1 ? 0.3 : 1 }}>
                        ✕
                      </button>
                    </div>
                  ))}
                </div>

                {form.venues.length > 0 && slots.filter((s) => s.showDate && s.startTime).length > 0 && (
                  <div style={{
                    marginTop: '10px', padding: '10px 14px', borderRadius: '8px',
                    background: 'var(--green-dim)', border: '1px solid rgba(0,214,143,0.2)',
                    fontSize: '12px', color: 'var(--green)',
                  }}>
                    💡 Will create <strong>{form.venues.length * slots.filter((s) => s.showDate && s.startTime).length}</strong> slot(s) automatically
                    — {form.venues.length} venue{form.venues.length > 1 ? 's' : ''} × {slots.filter((s) => s.showDate && s.startTime).length} date/time{slots.filter((s) => s.showDate && s.startTime).length > 1 ? 's' : ''}
                  </div>
                )}
              </div>
            )}

            <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
              <button onClick={() => setModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={save} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : editId ? 'Update Event' : 'Create Event & Slots →'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminEventsPage;
